                                        {renderToolButton('Prop List', <PixelIcon name="prop" primary={C.FOREST} secondary={C.PINK} />, () => addCard(CardType.PROP_TABLE))}
                                        {renderToolButton('Device Frames', <PixelIcon name="device" primary={C.FOREST} secondary={C.BURGUNDY} />, () => addCard(CardType.DEVICE_FRAME))}
                                        {renderToolButton('Palette Extract', <PixelIcon name="palette" primary={C.FOREST} secondary={C.PINK} />, () => addCard(CardType.PALETTE_EXTRACTOR))}
